parameters.jsCode:
const lead = $('SELECT or CREATE lead & user_session').last().json.result.lead;
const diasLimite = 3; // número de dias considerado como "recente"
const agora = new Date();

let precisaConfirmar = false;

if (lead.qualificacao_concluida_em) {
  const qualificadoEm = new Date(lead.qualificacao_concluida_em);
  if (!isNaN(qualificadoEm.getTime())) {
    const diffEmMs = agora.getTime() - qualificadoEm.getTime();
    precisaConfirmar = diffEmMs > diasLimite * 24 * 60 * 60 * 1000;
  }
}

return {
  qualificacao_finalizada_em: new Date(lead.qualificacao_concluida_em),
  precisa_confirmar_dados: precisaConfirmar
};

